text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "confirmed_decisions": [
      {
        "decision": "공개 배포 목표는 smoke 테스트가 통과할 경우 금요일 15:00 KST로 한다.",
        "context": "수요일은 최종 배포일이 아니라 내부 스트레치 목표로만 취급한다."
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 재검토한다.",
        "context": "무시하도록 스크립트를 바꾸는 방향은 채택하지 않았다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "수요일 공개 배포",
        "reason": "smoke 테스트가 먼저 통과되어야 한다는 반대가 있었고, 최종 목표로 채택되지 않았다."
      },
      {
        "proposal": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 변경",
        "reason": "논의 후 거절되었다."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 공개 배포",
        "status": "내부 스트레치 목표",
        "note": "최종 공개 배포 목표는 아니며, smoke 통과가 전제다."
      },
      {
        "goal": "README 설치 절차를 목요일까지 검토",
        "status": "가능하면 진행",
        "note": "소유자는 배정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 출시를 지연시킬 수 있다."
      },
      {
        "risk": "README 설치 절차가 오래되면 릴리스 노트가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      "최종 배포 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 언급할 것인가?"
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차 검토",
        "status": "검토 필요성만 언급되었고, 소유자와 확정 일정이 없다."
      },
      {
        "item": "Hara의 tarball 경로 확인",
        "status": "Minjun의 smoke 결과 게시 이후 수행하기로 했지만 정확한 마감은 정해지지 않았다."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "회의 노트에 명시"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 failure triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "회의 노트에 명시"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 게시한 뒤 generated tarball 경로를 확인한다.",
      "due": null,
      "status": "대기 중",
      "source_certainty": "회의 노트에 명시"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
      "due": null,
      "status": "미배정",
      "source_certainty": "원문에 제안만 있고 소유자가 배정되지 않음"
    }
  ],
  "followup_note": "다음 확인 대상은 smoke 결과, tarball 경로, 최종 배포 승인 권한자, 그리고 release note에 내부 수요일 목표를 적을지 여부다. 고객명, 외부 파트너명, 예산, 보안 사고, 운영 중단, 법적 승인 요구, 소유자, 마감일은 원문에 없으면 추가로 만들지 말아야 한다.",
  "non_invention_rules": [
    "고객명이나 외부 파트너명을 추정하지 않는다.",
    "예산, 보안 사고, 운영 중단, 법적 승인 요구를 추가하지 않는다.",
    "최종 배포 승인 권한자와 README 검토 소유자는 모르면 미정으로 둔다.",
    "확정되지 않은 날짜는 due로 단정하지 않는다.",
    "수요일은 내부 스트레치 목표로만 기록하고 최종 배포일로 격상하지 않는다.",
    "packageName 불일치 원인을 스크립트 결함으로 바로 단정하지 않는다.",
    "tarball 경로 문제는 위험으로만 기록하고 실제 장애로 확대하지 않는다."
  ]
}
